from __future__ import annotations


def sanitize_fields(fields, allowed, length_caps=None):
    output = []
    caps = length_caps or {}
    for field in fields:
        if field in output or field not in allowed:
            continue
        if not all(char.isalnum() or char == '_' for char in field):
            continue
        if field in caps and len(field) > caps[field]:
            continue
        output.append(field)
    return output

